# 구현 세부사항

## 파일 생성
- `lib/validations/event.ts`: Zod 스키마 정의
- `types/event.ts`: 공통 TypeScript 타입 정의

## Zod 스키마 (`lib/validations/event.ts`)

```typescript
import { z } from "zod";
import { Constants } from "@/types/database.types";

// 이벤트 생성 스키마
export const eventCreateSchema = z.object({
  title: z.string().min(2, "제목은 최소 2자 이상이어야 합니다").max(100, "제목은 최대 100자까지 가능합니다"),
  description: z.string().max(2000, "설명은 최대 2000자까지 가능합니다").optional(),
  category: z.enum(Constants.public.Enums.event_category),
  eventDate: z.string().refine((date) => new Date(date) > new Date(), "이벤트 날짜는 미래 날짜여야 합니다"),
  location: z.string().max(200, "장소는 최대 200자까지 가능합니다").optional(),
  maxParticipants: z.number().int().min(1).max(999).optional(),
  isPublic: z.boolean().default(true),
  coverImageUrl: z.string().url().optional(),
});

// 이벤트 수정 스키마 (모든 필드 선택적)
export const eventUpdateSchema = eventCreateSchema.partial();
```

## 공통 타입 (`types/event.ts`)

```typescript
import { z } from "zod";
import { Database, Constants } from "@/types/database.types";
import { eventCreateSchema, eventUpdateSchema } from "@/lib/validations/event";

// EventCategory 타입
export type EventCategory = Database["public"]["Enums"]["event_category"];

// 폼 데이터 타입
export type EventFormData = z.infer<typeof eventCreateSchema>;
export type EventUpdateFormData = z.infer<typeof eventUpdateSchema>;

// 이벤트 + 주최자 정보 조인 타입
export type EventWithHost = Database["public"]["Tables"]["events"]["Row"] & {
  host: {
    name: string | null;
    avatar_url: string | null;
  };
};

// 카테고리 배열 상수
export const EVENT_CATEGORIES = Constants.public.Enums.event_category as readonly EventCategory[];
```

## 주요 검증 규칙
- title: 2-100자 필수
- description: 0-2000자 선택
- category: ENUM 값 중 하나 필수
- eventDate: ISO 8601 형식, 미래 날짜 검증
- location: 0-200자 선택
- maxParticipants: 1-999 정수 선택
- isPublic: boolean, 기본값 true
- coverImageUrl: URL 형식 선택

# 구현 세부사항

## 1. Supabase Storage 버킷 생성

Supabase 대시보드에서 `event-covers` 버킷 생성:
- 공개 버킷으로 설정 (이미지는 누구나 조회 가능)
- RLS 정책: 인증된 사용자만 업로드/삭제 가능

SQL 마이그레이션으로 자동화 가능:
```sql
-- event-covers 버킷 생성
INSERT INTO storage.buckets (id, name, public)
VALUES ('event-covers', 'event-covers', true);

-- RLS 정책: 인증된 사용자만 업로드 가능
CREATE POLICY "Authenticated users can upload event covers"
ON storage.objects FOR INSERT
TO authenticated
WITH CHECK (bucket_id = 'event-covers');

-- RLS 정책: 파일 소유자만 삭제 가능
CREATE POLICY "Users can delete own event covers"
ON storage.objects FOR DELETE
TO authenticated
USING (bucket_id = 'event-covers' AND auth.uid()::text = (storage.foldername(name))[1]);
```

## 2. 이미지 업로드 유틸리티 (`lib/supabase/storage.ts`)

```typescript
import { createClient } from "@/lib/supabase/server";

const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const ALLOWED_MIME_TYPES = ["image/jpeg", "image/png", "image/webp"];

// 클라이언트 사이드 파일 검증
export function validateImageFile(file: File): { valid: boolean; error?: string } {
  if (file.size > MAX_FILE_SIZE) {
    return { valid: false, error: "파일 크기는 5MB 이하여야 합니다" };
  }
  if (!ALLOWED_MIME_TYPES.includes(file.type)) {
    return { valid: false, error: "JPG, PNG, WebP 형식만 업로드 가능합니다" };
  }
  return { valid: true };
}

// 이미지 업로드 후 공개 URL 반환
export async function uploadEventCoverImage(
  file: File,
  eventId: string
): Promise<string> {
  const supabase = await createClient();

  // 인증 확인
  const { data: { user }, error: authError } = await supabase.auth.getUser();
  if (authError || !user) {
    throw new Error("인증이 필요합니다");
  }

  // 파일 검증
  const validation = validateImageFile(file);
  if (!validation.valid) {
    throw new Error(validation.error);
  }

  // 파일 경로: event-covers/{eventId}/{timestamp}_{fileName}
  const timestamp = Date.now();
  const fileName = file.name.replace(/[^a-zA-Z0-9.-]/g, "_");
  const filePath = `${eventId}/${timestamp}_${fileName}`;

  // Storage 업로드
  const { data, error } = await supabase.storage
    .from("event-covers")
    .upload(filePath, file, {
      cacheControl: "3600",
      upsert: false,
    });

  if (error) {
    throw new Error(`이미지 업로드 실패: ${error.message}`);
  }

  // 공개 URL 반환
  const { data: { publicUrl } } = supabase.storage
    .from("event-covers")
    .getPublicUrl(data.path);

  return publicUrl;
}

// 기존 이미지 삭제
export async function deleteEventCoverImage(filePath: string): Promise<void> {
  const supabase = await createClient();

  const { error } = await supabase.storage
    .from("event-covers")
    .remove([filePath]);

  if (error) {
    throw new Error(`이미지 삭제 실패: ${error.message}`);
  }
}

// Storage 파일 경로로 공개 URL 생성
export function getEventCoverImageUrl(filePath: string): string {
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
  return `${supabaseUrl}/storage/v1/object/public/event-covers/${filePath}`;
}
```

## 3. next.config.ts 이미지 도메인 추가

```typescript
