# 구현 세부사항

## 파일 생성
- `actions/events.ts`: 이벤트 CRUD Server Actions
- `types/action.ts`: ActionResult 공통 타입

## ActionResult 타입 (`types/action.ts`)

```typescript
export type ActionResult = {
  success: boolean;
  error?: string;
  data?: any;
};
```

## Server Actions (`actions/events.ts`)

```typescript
"use server";

import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { createClient } from "@/lib/supabase/server";
import { eventCreateSchema, eventUpdateSchema } from "@/lib/validations/event";
import { uploadEventCoverImage, deleteEventCoverImage } from "@/lib/supabase/storage";
import type { ActionResult } from "@/types/action";
import type { EventWithHost } from "@/types/event";

// 이벤트 생성
export async function createEvent(formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();

  // 인증 확인
  const { data: { user }, error: authError } = await supabase.auth.getUser();
  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다" };
  }

  // FormData 파싱
  const rawData = {
    title: formData.get("title"),
    description: formData.get("description") || undefined,
    category: formData.get("category"),
    eventDate: formData.get("eventDate"),
    location: formData.get("location") || undefined,
    maxParticipants: formData.get("maxParticipants") ? Number(formData.get("maxParticipants")) : undefined,
    isPublic: formData.get("isPublic") === "true",
  };

  // Zod 검증
  const validation = eventCreateSchema.safeParse(rawData);
  if (!validation.success) {
    return { success: false, error: validation.error.errors[0].message };
  }

  const validatedData = validation.data;

  // 커버 이미지 처리
  let coverImageUrl: string | undefined;
  const coverImageFile = formData.get("coverImage") as File | null;
  if (coverImageFile && coverImageFile.size > 0) {
    try {
      // 임시 ID 생성 (실제 이벤트 생성 전)
      const tempEventId = crypto.randomUUID();
      coverImageUrl = await uploadEventCoverImage(coverImageFile, tempEventId);
    } catch (error) {
      return { success: false, error: error instanceof Error ? error.message : "이미지 업로드 실패" };
    }
  }

  // 이벤트 생성
  const { data: event, error: insertError } = await supabase
    .from("events")
    .insert({
      title: validatedData.title,
      description: validatedData.description,
      category: validatedData.category,
      event_date: validatedData.eventDate,
      location: validatedData.location,
      max_participants: validatedData.maxParticipants,
      is_public: validatedData.isPublic,
      cover_image_url: coverImageUrl,
      host_id: user.id,
    })
    .select()
    .single();

  if (insertError) {
    return { success: false, error: `이벤트 생성 실패: ${insertError.message}` };
  }

  revalidatePath("/(host)/events");
  redirect(`/(host)/events/${event.id}`);
}

// 이벤트 수정
export async function updateEvent(eventId: string, formData: FormData): Promise<ActionResult> {
  const supabase = await createClient();

  // 인증 확인
  const { data: { user }, error: authError } = await supabase.auth.getUser();
  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다" };
  }

  // 권한 확인
  const { data: event, error: fetchError } = await supabase
    .from("events")
    .select("host_id, cover_image_url")
    .eq("id", eventId)
    .single();

  if (fetchError || !event) {
    return { success: false, error: "이벤트를 찾을 수 없습니다" };
  }

  if (event.host_id !== user.id) {
    return { success: false, error: "이벤트를 수정할 권한이 없습니다" };
  }

  // FormData 파싱
  const rawData = {
    title: formData.get("title") || undefined,
    description: formData.get("description") || undefined,
    category: formData.get("category") || undefined,
    eventDate: formData.get("eventDate") || undefined,
    location: formData.get("location") || undefined,
    maxParticipants: formData.get("maxParticipants") ? Number(formData.get("maxParticipants")) : undefined,
    isPublic: formData.get("isPublic") ? formData.get("isPublic") === "true" : undefined,
  };

  // Zod 검증
  const validation = eventUpdateSchema.safeParse(rawData);
  if (!validation.success) {
    return { success: false, error: validation.error.errors[0].message };
  }

  const validatedData = validation.data;

  // 커버 이미지 교체 처리
  let coverImageUrl: string | undefined | null = undefined;
  const coverImageFile = formData.get("coverImage") as File | null;
  const removeCoverImage = formData.get("removeCoverImage") === "true";

  if (removeCoverImage) {
    // 기존 이미지 삭제
    if (event.cover_image_url) {
      try {
        const filePath = event.cover_image_url.split("/event-covers/")[1];
        await deleteEventCoverImage(filePath);
      } catch (error) {
        console.error("기존 이미지 삭제 실패:", error);
      }
    }
    coverImageUrl = null;
  } else if (coverImageFile && coverImageFile.size > 0) {
    // 새 이미지 업로드
    try {
      // 기존 이미지 삭제
      if (event.cover_image_url) {
        const filePath = event.cover_image_url.split("/event-covers/")[1];
        await deleteEventCoverImage(filePath);
      }
      coverImageUrl = await uploadEventCoverImage(coverImageFile, eventId);
    } catch (error) {
      return { success: false, error: error instanceof Error ? error.message : "이미지 업로드 실패" };
    }
  }

  // 이벤트 업데이트
  const updateData: any = {
    ...validatedData,
    event_date: validatedData.eventDate,
    max_participants: validatedData.maxParticipants,
    is_public: validatedData.isPublic,
  };

  if (coverImageUrl !== undefined) {
    updateData.cover_image_url = coverImageUrl;
  }

  const { error: updateError } = await supabase
    .from("events")
    .update(updateData)
    .eq("id", eventId);

  if (updateError) {
    return { success: false, error: `이벤트 수정 실패: ${updateError.message}` };
  }

  revalidatePath(`/(host)/events/${eventId}`);
  revalidatePath("/(host)/events");
  redirect(`/(host)/events/${eventId}`);
}

// 이벤트 삭제
export async function deleteEvent(eventId: string): Promise<ActionResult> {
  const supabase = await createClient();

  // 인증 확인
  const { data: { user }, error: authError } = await supabase.auth.getUser();
  if (authError || !user) {
    return { success: false, error: "로그인이 필요합니다" };
  }

  // 권한 확인
  const { data: event, error: fetchError } = await supabase
    .from("events")
    .select("host_id, cover_image_url")
    .eq("id", eventId)
    .single();

  if (fetchError || !event) {
    return { success: false, error: "이벤트를 찾을 수 없습니다" };
  }

  if (event.host_id !== user.id) {
    return { success: false, error: "이벤트를 삭제할 권한이 없습니다" };
  }

  // 커버 이미지 삭제
  if (event.cover_image_url) {
    try {
      const filePath = event.cover_image_url.split("/event-covers/")[1];
      await deleteEventCoverImage(filePath);
    } catch (error) {
      console.error("이미지 삭제 실패:", error);
    }
  }

  // 이벤트 삭제
  const { error: deleteError } = await supabase
    .from("events")
    .delete()
    .eq("id", eventId);

  if (deleteError) {
    return { success: false, error: `이벤트 삭제 실패: ${deleteError.message}` };
  }

  revalidatePath("/(host)/events");
  redirect("/(host)/events");
}

// 단일 이벤트 조회 (host 정보 포함)
export async function getEventById(eventId: string): Promise<EventWithHost | null> {
  const supabase = await createClient();

  const { data, error } = await supabase
    .from("events")
    .select(`
      *,
      host:profiles!host_id (
        name,
        avatar_url
      )
    `)
    .eq("id", eventId)
    .single();

  if (error || !data) {
    return null;
  }

  return data as unknown as EventWithHost;
}

// 내 이벤트 목록 조회
export async function getMyEvents(): Promise<EventWithHost[]> {
  const supabase = await createClient();

  const { data: { user } } = await supabase.auth.getUser();
  if (!user) {
    return [];
  }

  const { data, error } = await supabase
    .from("events")
    .select(`
      *,
      host:profiles!host_id (
        name,
        avatar_url
      )
    `)
    .eq("host_id", user.id)
    .order("created_at", { ascending: false });

  if (error || !data) {
    return [];
  }

  return data as unknown as EventWithHost[];
}

// 공개 이벤트 목록 조회
export async function getPublicEvents(category?: string): Promise<EventWithHost[]> {
  const supabase = await createClient();

  let query = supabase
    .from("events")
    .select(`
      *,
      host:profiles!host_id (
        name,
        avatar_url
      )
    `)
    .eq("is_public", true);

  if (category) {
    query = query.eq("category", category);
  }

  const { data, error } = await query.order("created_at", { ascending: false });

  if (error || !data) {
    return [];
  }

  return data as unknown as EventWithHost[];
}
```

# 구현 세부사항

## 파일 생성
- `components/forms/event-form.tsx`: 재사용 가능한 이벤트 폼 컴포넌트

## 구현 코드

```typescript
"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { useState, useTransition } from "react";
import { Loader2 } from "lucide-react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { eventCreateSchema } from "@/lib/validations/event";
import { validateImageFile } from "@/lib/supabase/storage";
import { createEvent, updateEvent } from "@/actions/events";
import { EVENT_CATEGORIES, type EventFormData } from "@/types/event";

type EventFormProps = {
  mode: "create" | "edit";
  defaultValues?: Partial<EventFormData>;
  eventId?: string;
};

export function EventForm({ mode, defaultValues, eventId }: EventFormProps) {
  const [isPending, startTransition] = useTransition();
  const [imagePreview, setImagePreview] = useState<string | null>(
    defaultValues?.coverImageUrl || null
  );

  const {
    register,
    handleSubmit,
    setValue,
    watch,
    formState: { errors },
  } = useForm<EventFormData>({
    resolver: zodResolver(eventCreateSchema),
    defaultValues: {
      isPublic: true,
      ...defaultValues,
    },
  });

  const isPublic = watch("isPublic");

  // 이미지 파일 선택 핸들러
  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // 클라이언트 검증
    const validation = validateImageFile(file);
    if (!validation.valid) {
      toast.error(validation.error);
      e.target.value = "";
      return;
    }

    // 미리보기 생성
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  // 폼 제출 핸들러
  const onSubmit = (data: EventFormData) => {
    startTransition(async () => {
      const formData = new FormData();
      formData.append("title", data.title);
      formData.append("category", data.category);
      formData.append("eventDate", data.eventDate);
      formData.append("isPublic", String(data.isPublic));

      if (data.description) formData.append("description", data.description);
      if (data.location) formData.append("location", data.location);
      if (data.maxParticipants) formData.append("maxParticipants", String(data.maxParticipants));

      // 이미지 파일 추가
      const fileInput = document.querySelector('input[name="coverImage"]') as HTMLInputElement;
      if (fileInput?.files?.[0]) {
        formData.append("coverImage", fileInput.files[0]);
      }

      try {
        if (mode === "create") {
          await createEvent(formData);
        } else if (mode === "edit" && eventId) {
          await updateEvent(eventId, formData);
        }
      } catch (error) {
        toast.error(error instanceof Error ? error.message : "오류가 발생했습니다");
      }
    });
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col gap-4">
      {/* 제목 */}
      <div>
        <Label htmlFor="title">이벤트 제목 *</Label>
        <Input
          id="title"
          {...register("title")}
          placeholder="이벤트 제목을 입력하세요"
        />
        {errors.title && (
          <p className="mt-1 text-sm text-destructive">{errors.title.message}</p>
        )}
      </div>

      {/* 카테고리 */}
      <div>
        <Label htmlFor="category">카테고리 *</Label>
        <Select
          onValueChange={(value) => setValue("category", value as any)}
          defaultValue={defaultValues?.category}
        >
          <SelectTrigger id="category">
            <SelectValue placeholder="카테고리 선택" />
          </SelectTrigger>
          <SelectContent>
            {EVENT_CATEGORIES.map((category) => (
              <SelectItem key={category} value={category}>
                {category}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {errors.category && (
          <p className="mt-1 text-sm text-destructive">{errors.category.message}</p>
        )}
      </div>

      {/* 일시 */}
      <div>
        <Label htmlFor="eventDate">일시 *</Label>
        <Input
          id="eventDate"
          type="datetime-local"
          {...register("eventDate")}
        />
        {errors.eventDate && (
          <p className="mt-1 text-sm text-destructive">{errors.eventDate.message}</p>
        )}
      </div>

      {/* 장소 */}
      <div>
        <Label htmlFor="location">장소</Label>
        <Input
          id="location"
          {...register("location")}
          placeholder="장소를 입력하세요"
        />
        {errors.location && (
          <p className="mt-1 text-sm text-destructive">{errors.location.message}</p>
        )}
      </div>

      {/* 최대 참여자 수 */}
      <div>
        <Label htmlFor="maxParticipants">최대 참여자 수</Label>
        <Input
          id="maxParticipants"
          type="number"
          min="1"
          max="999"
          {...register("maxParticipants", { valueAsNumber: true })}
          placeholder="제한 없음"
        />
        {errors.maxParticipants && (
          <p className="mt-1 text-sm text-destructive">{errors.maxParticipants.message}</p>
        )}
      </div>

      {/* 설명 */}
      <div>
        <Label htmlFor="description">설명</Label>
        <Textarea
          id="description"
          {...register("description")}
          placeholder="이벤트에 대해 설명해주세요"
          rows={4}
        />
        {errors.description && (
          <p className="mt-1 text-sm text-destructive">{errors.description.message}</p>
        )}
      </div>

      {/* 커버 이미지 */}
      <div>
        <Label htmlFor="coverImage">커버 이미지</Label>
        <Input
          id="coverImage"
          name="coverImage"
          type="file"
          accept="image/jpeg,image/png,image/webp"
          onChange={handleImageChange}
        />
        {imagePreview && (
          <div className="mt-2">
            <img
              src={imagePreview}
              alt="미리보기"
              className="h-40 w-full rounded-md object-cover"
            />
          </div>
        )}
        <p className="mt-1 text-xs text-muted-foreground">
          JPG, PNG, WebP 형식 / 최대 5MB
        </p>
      </div>

      {/* 공개/비공개 */}
      <div className="flex items-center gap-2">
        <Checkbox
          id="isPublic"
          checked={isPublic}
          onCheckedChange={(checked) => setValue("isPublic", checked as boolean)}
        />
        <Label htmlFor="isPublic" className="cursor-pointer">
          이벤트 공개 (누구나 탐색 페이지에서 볼 수 있습니다)
        </Label>
      </div>

      {/* 제출 버튼 */}
      <Button type="submit" disabled={isPending} className="w-full">
        {isPending ? (
          <>
            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
            {mode === "create" ? "생성 중..." : "수정 중..."}
          </>
        ) : (
          <>{mode === "create" ? "이벤트 만들기" : "수정 완료"}</>
        )}
      </Button>
    </form>
  );
}
```

