```typescript
import Link from "next/link";
import { format, formatDistanceToNow, isPast } from "date-fns";
import { ko } from "date-fns/locale";
import { Calendar, MapPin, Users } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { EventCategoryBadge } from "@/components/mobile/event-category-badge";
import { cn } from "@/lib/utils";
import type { EventWithHost } from "@/types/event";

type EventCardMobileProps = {
  event: EventWithHost;
  href: string;
  showNewBadge?: boolean;
};

export function EventCardMobile({ event, href, showNewBadge = false }: EventCardMobileProps) {
  const eventDate = new Date(event.event_date);
  const isEventPast = isPast(eventDate);
  const isNew = showNewBadge && Date.now() - new Date(event.created_at!).getTime() < 24 * 60 * 60 * 1000;

  // 날짜 상대적 표시 ("3일 후", "내일", "오늘" 등)
  const relativeDateText = formatDistanceToNow(eventDate, {
    addSuffix: true,
    locale: ko,
  });

  // 절대 날짜 표시
  const absoluteDateText = format(eventDate, "yyyy년 M월 d일 (E) HH:mm", { locale: ko });

  return (
    <Link href={href}>
      <Card className={cn("overflow-hidden transition-shadow hover:shadow-md", isEventPast && "opacity-60")}>
        {/* 커버 이미지 */}
        <div className="relative h-32 w-full bg-gradient-to-br from-primary/20 to-primary/5">
          {event.cover_image_url ? (
            <img
              src={event.cover_image_url}
              alt={event.title}
              className="h-full w-full object-cover"
            />
          ) : (
            <div className="flex h-full items-center justify-center">
              <Calendar className="h-12 w-12 text-primary/40" />
            </div>
          )}
          {/* NEW 배지 */}
          {isNew && (
            <div className="absolute left-2 top-2 rounded-full bg-red-500 px-2 py-0.5 text-xs font-bold text-white">
              NEW
            </div>
          )}
          {/* 카테고리 배지 */}
          <div className="absolute bottom-2 left-2">
            <EventCategoryBadge category={event.category} />
          </div>
        </div>

        <CardContent className="p-3">
          {/* 제목 */}
          <h3 className="line-clamp-2 text-base font-semibold text-foreground">
            {event.title}
          </h3>

          {/* 일시 */}
          <div className="mt-2 flex items-center gap-1 text-xs text-muted-foreground">
            <Calendar className="h-3 w-3" />
            <span>{relativeDateText}</span>
          </div>

          {/* 장소 */}
          {event.location && (
            <div className="mt-1 flex items-center gap-1 text-xs text-muted-foreground">
              <MapPin className="h-3 w-3" />
              <span className="line-clamp-1">{event.location}</span>
