          {/* 참여 현황 (placeholder) */}
          {event.max_participants && (
            <div className="mt-1 flex items-center gap-1 text-xs text-muted-foreground">
              <Users className="h-3 w-3" />
              <span>최대 {event.max_participants}명</span>
            </div>
          )}
        </CardContent>
      </Card>
    </Link>
  );
}
