      await navigator.clipboard.writeText(url);
      setCopied(true);
      toast.success("초대 링크가 복사되었습니다");
      setTimeout(() => setCopied(false), 2000);
    } catch (error) {
      toast.error("링크 복사에 실패했습니다");
    }
  };

  return (
    <Button
      variant="outline"
      size="sm"
      onClick={handleCopy}
      className="gap-2"
    >
      {copied ? (
        <>
          <Check className="h-4 w-4" />
          복사됨!
        </>
      ) : (
        <>
          <LinkIcon className="h-4 w-4" />
          초대 링크 복사
        </>
      )}
    </Button>
  );
}
