## 구현 상세

### 파일 수정
- `components/forms/event-form.tsx` - datetime-local input 값 변환 로직 추가
- `lib/utils.ts` - UTC → KST 변환 유틸리티 함수 추가 (또는 신규 파일)

### 기술 사항
1. **문제 원인**
   - DB의 `event_date` 컬럼은 UTC로 저장됨 (`timestamptz` 타입)
   - `<input type="datetime-local">`은 로컬 시간 문자열을 기대함 (YYYY-MM-DDTHH:mm)
   - 현재 UTC 값을 그대로 전달하여 9시간 차이 발생

2. **유틸리티 함수 작성**
   ```typescript
   // lib/utils.ts에 추가 또는 lib/date-utils.ts 신규 생성

   /**
    * UTC ISO 문자열을 KST(UTC+9) 기준 datetime-local 포맷으로 변환
    * @param utcIsoString - UTC ISO 8601 문자열 (예: "2026-03-22T10:00:00.000Z")
    * @returns YYYY-MM-DDTHH:mm 포맷 문자열 (예: "2026-03-22T19:00")
    */
   export function utcToKstDatetimeLocal(utcIsoString: string): string {
     const date = new Date(utcIsoString);

     // KST는 UTC+9
     const kstOffset = 9 * 60; // 분 단위
     const localOffset = date.getTimezoneOffset(); // 현재 로컬 오프셋 (분, UTC보다 뒤면 양수)

     // KST 시간 계산
     const kstTime = new Date(date.getTime() + (kstOffset + localOffset) * 60 * 1000);

     // YYYY-MM-DDTHH:mm 포맷으로 변환
     const year = kstTime.getFullYear();
     const month = String(kstTime.getMonth() + 1).padStart(2, '0');
     const day = String(kstTime.getDate()).padStart(2, '0');
     const hours = String(kstTime.getHours()).padStart(2, '0');
     const minutes = String(kstTime.getMinutes()).padStart(2, '0');

     return `${year}-${month}-${day}T${hours}:${minutes}`;
   }

   /**
    * datetime-local 포맷 문자열을 UTC ISO 문자열로 변환 (저장용)
    * @param datetimeLocal - YYYY-MM-DDTHH:mm 포맷 문자열
    * @returns UTC ISO 8601 문자열
    */
   export function kstDatetimeLocalToUtc(datetimeLocal: string): string {
     // datetime-local 값은 사용자의 로컬 시간대로 해석됨
     // KST 기준으로 해석하려면 명시적 변환 필요
     const [datePart, timePart] = datetimeLocal.split('T');
     const kstDate = new Date(`${datePart}T${timePart}:00+09:00`);
     return kstDate.toISOString();
   }
   ```

3. **date-fns 라이브러리 활용 (권장)**
   - 이미 설치된 `date-fns` 사용
   - `date-fns-tz`는 미설치 상태이므로 수동 오프셋 계산 또는 추가 설치

   ```typescript
   // date-fns 활용 버전
   import { format, addHours } from 'date-fns';

   export function utcToKstDatetimeLocal(utcIsoString: string): string {
     const utcDate = new Date(utcIsoString);
     const kstDate = addHours(utcDate, 9); // UTC+9
     return format(kstDate, "yyyy-MM-dd'T'HH:mm");
   }
   ```

