### 기술 사항
1. **BackButton Client Component 생성**
   ```typescript
   // components/shared/back-button.tsx
   'use client';

   import { ChevronLeft } from 'lucide-react';
   import { useRouter } from 'next/navigation';
   import { Button } from '@/components/ui/button';
   import { cn } from '@/lib/utils';

   type BackButtonProps = {
     className?: string;
     fallbackHref?: string; // 뒤로가기 이력이 없을 때 이동할 경로
     variant?: 'default' | 'ghost' | 'overlay'; // overlay: 커버 이미지 위 오버레이 스타일
   };

   export function BackButton({ 
     className, 
     fallbackHref = '/events',
     variant = 'ghost' 
   }: BackButtonProps) {
     const router = useRouter();

     const handleBack = () => {
       // window.history.length로 뒤로가기 가능 여부 판단
       if (window.history.length > 1) {
         router.back();
       } else {
         router.push(fallbackHref);
       }
     };

     const buttonVariant = variant === 'overlay' ? 'ghost' : variant;
     const buttonClasses = cn(
       variant === 'overlay' && 'absolute left-4 top-4 z-10 bg-black/40 text-white hover:bg-black/60',
       className
     );

     return (
       <Button
         onClick={handleBack}
         variant={buttonVariant}
         size="icon"
         className={buttonClasses}
         aria-label="뒤로가기"
       >
         <ChevronLeft className="h-5 w-5" />
       </Button>
     );
   }
   ```

