   ```typescript
   // components/shared/toast-handler.tsx
   'use client';

   import { useEffect } from 'react';
   import { useRouter, useSearchParams } from 'next/navigation';
   import { toast } from 'sonner';

   type ToastHandlerProps = {
     successMessages?: {
       created?: string;
       updated?: string;
       deleted?: string;
     };
   };

   export function ToastHandler({ 
     successMessages = {
       created: '이벤트가 생성되었습니다',
       updated: '이벤트가 수정되었습니다',
       deleted: '이벤트가 삭제되었습니다',
     }
   }: ToastHandlerProps) {
     const searchParams = useSearchParams();
     const router = useRouter();

     useEffect(() => {
       const created = searchParams.get('created');
       const updated = searchParams.get('updated');
       const deleted = searchParams.get('deleted');

       if (created === 'true') {
         toast.success(successMessages.created);
         // URL에서 파라미터 제거
         const url = new URL(window.location.href);
         url.searchParams.delete('created');
         router.replace(url.pathname + url.search);
       } else if (updated === 'true') {
         toast.success(successMessages.updated);
         const url = new URL(window.location.href);
         url.searchParams.delete('updated');
         router.replace(url.pathname + url.search);
       } else if (deleted === 'true') {
         toast.success(successMessages.deleted);
         const url = new URL(window.location.href);
         url.searchParams.delete('deleted');
         router.replace(url.pathname + url.search);
       }
     }, [searchParams, router, successMessages]);

     return null; // UI 렌더링 없음
   }
   ```

